package net.glassless.provider;

import static net.glassless.provider.GlaSSLessProvider.PROVIDER_NAME;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;
import static org.junit.jupiter.api.Assumptions.assumeTrue;

import java.security.InvalidKeyException;
import java.security.KeyFactory;
import java.security.PublicKey;
import java.security.Security;
import java.security.Signature;
import java.security.spec.X509EncodedKeySpec;
import java.util.HexFormat;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;

import net.glassless.provider.internal.OpenSSLCrypto;

/**
 * Tests for LMS (Leighton-Micali Signature) verification.
 * LMS is a stateful hash-based post-quantum signature scheme (RFC 8554 / NIST SP 800-208).
 * Only verification is supported.
 * Tests will be skipped if OpenSSL 3.6+ with LMS support is not available.
 *
 * <p>Test vectors are from OpenSSL's ACVP test data (evppkey_lms_sigver.txt),
 * originally generated from NIST ACVP Server test vectors.
 */
public class LMSTest {

   @BeforeAll
   public static void setUp() {
      Security.addProvider(new GlaSSLessProvider());
   }

   private static void assumeLMSAvailable() {
      assumeTrue(OpenSSLCrypto.isAlgorithmAvailable("KEYMGMT", "LMS"),
         "LMS requires OpenSSL 3.6+ with LMS support (enable-lms)");
   }

   // ACVP test vector: LMS_SHA256_M24_H5, LMOTS_SHA256_N24_W1
   // Raw public key (48 bytes): type(4) + ots_type(4) + id(16) + K(24)
   private static final String RAW_PUBLIC_KEY_HEX =
      "0000000A00000005009240BF00A8FC86911C708EB1676D8A9728B266E3DD7CF4B63B21038ED8F9F4ED1041ED7DC9C010";

   // Message to verify
   private static final String MESSAGE_HEX =
      "ADC932E7E935E18551862358E29DE161E3F7487490F0E63783C07D03ABB872EB" +
      "84E2B58514DA15FECBA1D904990EAB8ECC5FC56F4F8903634E46C2FE33AD272B" +
      "8BBD678D2BADC0A96697FE9354357E46BEB1B0D2E4FDA8EB6FE132D4847C95CA" +
      "352E3A17546A3F7C31AA6DF8757344811B467AC9785C5AC5D4BBF76B2AF254D3";

   // Valid signature for the above message
   private static final String SIGNATURE_HEX =
      "0000001F00000005F748D8A3567E7E9C322886FF7889A407F7A67E640B376525" +
      "80E10E78948DCD00A052B050B963B05980E5583FFBDA57C3C7D29BCDBC8D8FA6" +
      "B2CCFF0B813C2C6F3DC99AC19272841FC973C60792FECB60F14735DCC6EE3569" +
      "668A6566942BEBFAF68AD056121C28889D3C5C44FD0CB2937CC486559997A0CB" +
      "398B5D7AB8AFDBC5905BD61D1A86AAAAEA1E617767C715394C131A87412219FE" +
      "7AEB4EBA09FC0682D618A1ACCB87FBD2B70CAEEE6C126523104C9E86A2C9360D" +
      "5241F4579CB1679E390371546BB3941B6F4EC398DF04F1F008C192992D4C7FD5" +
      "3D0E0F8116B3CC97746055AB0B3E323A7332CDD9F073FAE376DA5E44637A4973" +
      "50479A10195A6CCC444B630815FA2A504B47114A6E0B60AA33BF2A9D0BCC7585" +
      "";

   /**
    * Build an LMS SubjectPublicKeyInfo DER encoding from a raw LMS public key.
    * The SPKI format prepends a 24-byte header (20 bytes ASN.1 + 4 bytes HSS header).
    */
   private static byte[] buildSPKI(byte[] rawKey) {
      // Determine hash output size from raw key length:
      // raw = 4 (lms_type) + 4 (ots_type) + 16 (id) + n (K)
      // n = rawKey.length - 24
      int n = rawKey.length - 24;

      // HSS_LMS_HEADER(n):
      // 0x30, 0x2E+n, 0x30, 0x0d,
      // 0x06, 0x0b,
      // OID: 0x2a, 0x86, 0x48, 0x86, 0xf7, 0x0d, 0x01, 0x09, 0x10, 0x03, 0x11,
      // 0x03, 0x1D+n,
      // 0x00,
      // HSS levels: 0x00, 0x00, 0x00, 0x01
      byte[] header = new byte[] {
         0x30, (byte) (0x2E + n), 0x30, 0x0d,
         0x06, 0x0b,
         0x2a, (byte) 0x86, 0x48, (byte) 0x86, (byte) 0xf7, 0x0d, 0x01, 0x09, 0x10, 0x03, 0x11,
         0x03, (byte) (0x1D + n),
         0x00,
         0x00, 0x00, 0x00, 0x01
      };

      byte[] spki = new byte[header.length + rawKey.length];
      System.arraycopy(header, 0, spki, 0, header.length);
      System.arraycopy(rawKey, 0, spki, header.length, rawKey.length);
      return spki;
   }

   @Test
   @DisplayName("LMS algorithm is available when OpenSSL supports it")
   void testAlgorithmAvailable() {
      assumeLMSAvailable();

      // If we get here, the algorithm is available
      assertTrue(OpenSSLCrypto.isAlgorithmAvailable("KEYMGMT", "LMS"));
   }

   @Test
   @DisplayName("LMS KeyFactory can load public key from X.509 encoding")
   void testKeyFactoryLoadPublicKey() throws Exception {
      assumeLMSAvailable();

      byte[] rawKey = HexFormat.of().parseHex(RAW_PUBLIC_KEY_HEX);
      byte[] spki = buildSPKI(rawKey);

      KeyFactory kf = KeyFactory.getInstance("LMS", PROVIDER_NAME);
      assertNotNull(kf);

      PublicKey pubKey = kf.generatePublic(new X509EncodedKeySpec(spki));
      assertNotNull(pubKey);
      assertTrue("LMS".equalsIgnoreCase(pubKey.getAlgorithm()));
      assertNotNull(pubKey.getEncoded());
   }

   @Test
   @DisplayName("LMS Signature rejects signing")
   void testSigningNotSupported() throws Exception {
      assumeLMSAvailable();

      Signature sig = Signature.getInstance("LMS", PROVIDER_NAME);
      assertNotNull(sig);

      // Signing should throw
      assertThrows(InvalidKeyException.class, () -> sig.initSign(null));
   }

   @Test
   @DisplayName("LMS verify valid signature")
   void testVerifyValidSignature() throws Exception {
      assumeLMSAvailable();

      HexFormat hex = HexFormat.of();
      byte[] rawKey = hex.parseHex(RAW_PUBLIC_KEY_HEX);
      byte[] spki = buildSPKI(rawKey);
      byte[] message = hex.parseHex(MESSAGE_HEX);
      byte[] signature = hex.parseHex(SIGNATURE_HEX);

      KeyFactory kf = KeyFactory.getInstance("LMS", PROVIDER_NAME);
      PublicKey pubKey = kf.generatePublic(new X509EncodedKeySpec(spki));

      Signature sig = Signature.getInstance("LMS", PROVIDER_NAME);
      sig.initVerify(pubKey);
      sig.update(message);
      boolean valid = sig.verify(signature);

      assertTrue(valid, "Valid LMS signature should verify successfully");
   }

   @Test
   @DisplayName("LMS verify with modified message fails")
   void testVerifyModifiedMessage() throws Exception {
      assumeLMSAvailable();

      HexFormat hex = HexFormat.of();
      byte[] rawKey = hex.parseHex(RAW_PUBLIC_KEY_HEX);
      byte[] spki = buildSPKI(rawKey);
      byte[] message = hex.parseHex(MESSAGE_HEX);
      byte[] signature = hex.parseHex(SIGNATURE_HEX);

      // Modify message
      message[0] ^= 0xFF;

      KeyFactory kf = KeyFactory.getInstance("LMS", PROVIDER_NAME);
      PublicKey pubKey = kf.generatePublic(new X509EncodedKeySpec(spki));

      Signature sig = Signature.getInstance("LMS", PROVIDER_NAME);
      sig.initVerify(pubKey);
      sig.update(message);
      boolean valid = sig.verify(signature);

      assertFalse(valid, "Modified message should fail verification");
   }

   @Test
   @DisplayName("LMS verify with modified signature fails")
   void testVerifyModifiedSignature() throws Exception {
      assumeLMSAvailable();

      HexFormat hex = HexFormat.of();
      byte[] rawKey = hex.parseHex(RAW_PUBLIC_KEY_HEX);
      byte[] spki = buildSPKI(rawKey);
      byte[] message = hex.parseHex(MESSAGE_HEX);
      byte[] signature = hex.parseHex(SIGNATURE_HEX);

      // Modify signature
      signature[signature.length - 1] ^= 0xFF;

      KeyFactory kf = KeyFactory.getInstance("LMS", PROVIDER_NAME);
      PublicKey pubKey = kf.generatePublic(new X509EncodedKeySpec(spki));

      Signature sig = Signature.getInstance("LMS", PROVIDER_NAME);
      sig.initVerify(pubKey);
      sig.update(message);
      boolean valid = sig.verify(signature);

      assertFalse(valid, "Modified signature should fail verification");
   }

   @Test
   @DisplayName("LMS KeyFactory getKeySpec returns X509EncodedKeySpec")
   void testGetKeySpec() throws Exception {
      assumeLMSAvailable();

      byte[] rawKey = HexFormat.of().parseHex(RAW_PUBLIC_KEY_HEX);
      byte[] spki = buildSPKI(rawKey);

      KeyFactory kf = KeyFactory.getInstance("LMS", PROVIDER_NAME);
      PublicKey pubKey = kf.generatePublic(new X509EncodedKeySpec(spki));

      X509EncodedKeySpec spec = kf.getKeySpec(pubKey, X509EncodedKeySpec.class);
      assertNotNull(spec);
      assertNotNull(spec.getEncoded());
   }

   @Test
   @DisplayName("LMS KeyFactory rejects private key generation")
   void testPrivateKeyRejected() throws Exception {
      assumeLMSAvailable();

      KeyFactory kf = KeyFactory.getInstance("LMS", PROVIDER_NAME);
      assertThrows(Exception.class, () ->
         kf.generatePrivate(new java.security.spec.PKCS8EncodedKeySpec(new byte[]{0})));
   }
}
